INPUT_Config_0_detectandintercept_hints_:
var width = Math.min(Stage.width * 0.75, Stage.height * 0.5625, 400);
var height = 3 * (width / 4);

$this.size(width, height);

if (Math.min(Stage.width, Stage.height) < 768) {
  if (Stage.width > Stage.height) {
    // Mobile landscape: right center
    $this.x = Stage.width - $this.width;
    $this.y = Stage.height / 2 - $this.height / 2;
  } else {
    // Mobile portrait: center top
    $this.x = Stage.width / 2 - $this.width / 2;
    $this.y = 0;
  }
} else {
  // Desktop: center bottom
  $this.x = Stage.width / 2 - $this.width / 2;
  $this.y = Stage.height * 0.94 - $this.height;
}

