// Example animation that upgrades this stack to 'threat level 3'

const PI = 3.1416;
const threatLevel = 4;
const delay = 200;

// Server stack
//${stack1}.shader.tween('uThreatIntensity', threatLevel, 800, 'easeOutQuint');
${stack1}.shader.uniforms.uThreatIntensity.value = threatLevel;
${stack1}.shader.tween('uUpgradeFlash', 1, 400, 'easeOutCubic').onComplete(function() {
    ${stack1}.shader.tween('uUpgradeFlash', 0, 1500, 'easeInOutCubic');
});
${stack1}.shader.tween('uRotation', PI * 1.0, 4000, 'easeOutExpo').onComplete(function() {
    ${stack1}.shader.uniforms.uRotation.value = 0.0;
});

// Sprawling lines
${lines1}.shader.tween('uBrightness', 0, 200, 'easeInOutSine').onComplete(function() {
   ${lines1}.shader.tween('uBrightness', 1, 1300, 'easeInExpo');
});
${lines1}.shader.tween('uUpgradeFlash', 1, 300, 'easeOutSine', 100).onComplete(function() {
    ${lines1}.shader.tween('uUpgradeFlash', 0, 1500, 'easeInOutCubic', 400);
});
${lines1}.shader.tween('uUpgradeOffset', 11.0, 3000, 'easeOutExpo', 100).onComplete(function() {
    ${lines1}.shader.uniforms.uUpgradeOffset.value = 0.0;
    // ${lines1}.shader.tween('uUpgradeOffset', -20.0, 2000, 'easeInOutSine')
});
${lines1}.shader.tween('uThreatIntensity', threatLevel, 1, 'easeOutCubic', delay);

// Square pulse
${square1}.shader.tween('uScale', 3.0, 1500, 'easeOutExpo', 200).onComplete(function() {
    ${square1}.shader.uniforms.uScale.value = 0.0;
});
${square1}.shader.tween('uOffset', 5.0, 1400, 'easeInExpo', 300).onComplete(function() {
    ${square1}.shader.uniforms.uOffset.value = 0.0;
});

