#require(curl.glsl)
#require(simplenoise.glsl)
#require(eases.glsl)

vec3 terrain = texture2D(t3DShape, uv).xyz;
vec3 oterrain = terrain;

vec3 curl = curlNoise(terrain * uCurlNoiseScale*  0.1  + (time * uCurlTimeScale * 0.1));
terrain += curl * uCurlNoiseSpeed;

terrain.y += cnoise(terrain * uYScale * 0.001 + (time*0.1*uYTime)) * uYStrength;

vec3 shapeOrigin = texture2D(tShape3D, uv).xyz;
vec3 shape3d = (shapeOrigin * u3DShapeScale) + uShapePos;

vec3 target = terrain;

if (uShapeAmount > random.x && oterrain.z < uShapeZ) {
    float mixValue = rangeTransition(uTransition, crange(shapeOrigin.y, -2.5, 2.5, 0.0, 1.0), uTransitionPadding);

    if (uTransition > 0.0 && uTransition < 1.0) {
        vec3 curl2 = curlNoise(shape3d * uSCurlNoiseScale*  0.1  + (time * uSCurlTimeScale * 0.1));
        shape3d += curl2 * mixValue * uSCurlNoiseSpeed * (1.0 - uTransition);
    }

    target = mix(target, shape3d, sineOut(mixValue));

    if (uTransition > 0.0 && uTransition < 1.0) {
        vec3 curl3 = curlNoise(shape3d * uTCurlNoiseScale*  0.1  + (time * uTCurlTimeScale * 0.1));
        target += curl3 * mixValue * uTCurlNoiseSpeed * (1.0 - uTransition);
    }
}

pos += (target - pos) * 0.07;

