swirl += uSwirlCenter;

float lengthFromSettle = length(pos.xz);
if (lengthFromSettle > 0.02) shape.y += cnoise(shape * uYScale * 0.001 + (time * 0.1 * uYTime)) * uYStrength * crange(lengthFromSettle, 5.0, 10.0, 0.0, 1.0);

float modifiedTransition = uTransition;


if (modifiedTransition < 0.999) {
	swirl += curlNoise(swirl * uSwirlNoiseScale * 0.1 + (time * 0.1 * uSwirlTimeScale)) * uSwirlNoiseSpeed;
}


float axis = uTransitionAxis < 0.1 ? moshape.x : moshape.y;
if (uTransitionAxis > 1.9) axis = moshape.z;
if (uTransitionAxis > 2.9) axis = length(mix(shape, moshape, uWorldSpace));
// float axis = length(cameraPosition - moshape);

float boundTransition = crange(axis, uShapeBound.x, uShapeBound.y, 0.0, 1.0);
if (uBoundReverse > 0.5) boundTransition = 1.0 - boundTransition;
float mixValue = rangeTransition(modifiedTransition, boundTransition, uTransitionPadding);
if (uGazeRadius.x > 0.0) {
    mixValue *= texture2D(tGazeDistortion, uv).x;
}

if (modifiedTransition > 0.0 && modifiedTransition < 1.0) {
    vec3 curl2 = curlNoise(shape * uSCurlNoiseScale*  0.1  + (time * uSCurlTimeScale * 0.1));
    shape += curl2 * mixValue * uSCurlNoiseSpeed * (1.0 - modifiedTransition);
