// depth += crange(depth, 0.0, 0.01, 1.0, 0.0);

vec3 shape = origin;
shape.z = - depth * uDepth;

vec3 blob = crange(random.xyz, vec3(0.0), vec3(1.0), vec3(-1.0), vec3(1.0));
vec3 curl = curlNoise(blob * uCurlNoiseScale * 0.1  + (time * uCurlTimeScale * 0.1));
// blob *= curl * uCurlNoiseSpeed;
// blob *= 0.5;
blob = curl;

vec3 target = blob;

float mixValue = rangeTransition(uTransition, origin.y, uTransitionPadding);

// Curl noise toward bottom of hologram
// float mixValue = crange(st.y, uTransition, uTransition - uTransitionPadding, 0.0, 1.0);
mixValue += sineIn(crange(st.y, uBottomFadeEnd, 0.0, 0.0, 1.0)) * uBottomFadePower;

target = mix(blob, shape, mixValue);

if (uTransition > 0.0 && uTransition < 1.0) {
    vec3 curl2 = curlNoise(shape * uTCurlNoiseScale*  0.1  + (time * uTCurlTimeScale * 0.1));
    target += curl2 * mixValue * uTCurlNoiseSpeed * (1.0 - uTransition);
}

pos += (target - pos) * uLerpStrength;

//Ripple animtion
vec3 rippleVector = vec3(0., 1., 0.);
vec3 ripplePos = pos - vec3(0.5, 0., 0.);

//The ripples are plannar, these rotations allow to make the ripples
//in any direction.
float c = cos(radians(uRippleAngle.x));
float s = sin(radians(uRippleAngle.x));
mat3 rotationX = mat3(1., 0., 0., 0., c, s, 0., -s, c);

c = cos(radians(uRippleAngle.y));
s = sin(radians(uRippleAngle.y));
mat3 rotationY = mat3(c, 0., s, 0., 1., 0., -s, 0., c);

rippleVector = rotationY * rotationX * rippleVector;

//Radial distance from the origin of the sound.
float ll = length(ripplePos.xyz);

//amplitude limited by the radial distance
float amplitude = uRippleAmplitude * clamp(uRippleRadialLength - ll, 0., uRippleRadialLength) / uRippleRadialLength;

//amplitude limited by the height distance
amplitude *= clamp(uRippleHeightLength - abs(ripplePos.y), 0., uRippleHeightLength) / uRippleHeightLength;

//wave ripple
vec3 ripple = amplitude * sin(uRippleFrequency * ll - uRippleSpeed * time) * rippleVector;

