//Keys: e, tip, line
let scale = ${e}.tipScale;
${tip}.scale.setScalar(0);
${line}.shader.set('uTransition', 0);
${line}.shader.set('uEnd', 0);
${tip}.shader.set('uAlpha', 1);

var tipEnd, particles;
tween(${tip}.scale, {x: scale, y: scale, z: scale}, 300, 'easeOutExpo');
${line}.shader.tween('uTransition', 1, e.time, 'linear').onUpdate(value => {
    if (value > 0.98 && !tipEnd) {
        tipEnd = true;
        ${tip}.shader.tween('uAlpha', 0, 300, 'easeOutExpo');
        tween(${tip}.scale, {x: 5, y: 5, z: 5}, 400, 'easeOutExpo');
        ${line}.shader.tween('uEnd', 1, 400, 'easeOutExpo');
    }

    if (value > 0.96 && !particles) {
        CyberAttackVisuals.particles.explode(${tip}.getWorldPosition(), ${e}.color);
    }
});

